#!/usr/bin/env node
// Milestone notifier — generates a LinkedIn-ready post template + opens celebration issue when star milestones hit.
// NO Twitter/Discord webhooks (user opted out).
// NO auto-DM, NO off-platform action — output is manual copy/paste.

import { execSync } from 'node:child_process';
import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname } from 'node:path';

const REPO = process.env.REPO || 'theihtisham/agent-shadow-brain';
const STATE_PATH = '.github/.milestone-state.json';
const LINKEDIN_TEMPLATE_PATH = 'docs/launch/LINKEDIN_MILESTONE_POST.md';
const MILESTONES = [10, 25, 50, 100, 250, 500, 1000, 2500, 5000, 10000, 25000, 50000, 100000];

const stars = (() => {
  try {
    return JSON.parse(execSync(`gh api repos/${REPO} --jq '.stargazers_count'`, { encoding: 'utf-8' }));
  } catch { return 0; }
})();

let state = { lastMilestone: 0 };
if (existsSync(STATE_PATH)) {
  try { state = JSON.parse(readFileSync(STATE_PATH, 'utf-8')); } catch {}
}

const newest = MILESTONES.filter(m => m <= stars && m > state.lastMilestone).pop();
if (!newest) {
  console.log(`No new milestone. Stars: ${stars}, last fired: ${state.lastMilestone}`);
  process.exit(0);
}

// LinkedIn post template — user copies and posts manually
const linkedInPost = `# LinkedIn Post Template — ${newest.toLocaleString()} Stars Milestone

_Auto-generated by the Viral Amplifier on ${new Date().toISOString().slice(0, 10)}._

---

## Copy/paste this into LinkedIn

\`\`\`
🎉 Agent Shadow Brain just crossed ${newest.toLocaleString()} GitHub stars.

Thank you to every developer who starred, forked, opened an issue, or shared the project.

For those just discovering it: Shadow Brain is the singleton intelligence layer that gives every AI coding agent on your machine — Claude Code, Cursor, Cline, Codex, GitHub Copilot, Windsurf, Aider — shared memory across sessions and projects.

What one agent learns, every agent knows.

The whole thing installs in 30 seconds:
npx @theihtisham/agent-shadow-brain attach-all

Open source, MIT, TypeScript. Built solo over the last few months.

Currently at ${stars.toLocaleString()} stars and growing.

If you've been thinking about trying it — now's a good moment.

⭐ Repo: github.com/${REPO}

#OpenSource #DeveloperTools #ClaudeCode #Cursor #AIAgents #AICoding
\`\`\`

---

## Posting Tips

- Best time: Tuesday-Thursday, 8-10am your local time
- Add 1-2 screenshots in the post (drag/drop into LinkedIn editor):
  - The 30-second \`attach-all\` install demo
  - The Star History chart (https://api.star-history.com/svg?repos=${REPO}&type=Date)
- Reply to the first 5 comments within an hour — boosts the algorithm
- DON'T tag random people. DO tag people who actually use the project (check stargazers list)

## Anti-Patterns

- ❌ Don't claim viral status until you have ≥1k stars (looks insecure at <1k)
- ❌ Don't post the same content on LinkedIn twice in 30 days
- ❌ Don't ask for stars directly — let the post speak for itself
`;

mkdirSync(dirname(LINKEDIN_TEMPLATE_PATH), { recursive: true });
writeFileSync(LINKEDIN_TEMPLATE_PATH, linkedInPost);

// Open a GitHub issue to notify the maintainer
try {
  execSync(`gh issue create --title "🎉 Milestone — ${newest.toLocaleString()} stars" --body "Agent Shadow Brain just hit ${newest.toLocaleString()} stars (currently at ${stars.toLocaleString()}).

A LinkedIn post template has been generated at:
[docs/launch/LINKEDIN_MILESTONE_POST.md](../blob/main/docs/launch/LINKEDIN_MILESTONE_POST.md)

**Suggested manual actions:**
- Copy the LinkedIn post template and post to your network
- Update the README banner with the new star count
- Thank top 10 recent stargazers individually (\`gh api repos/${REPO}/stargazers --jq '.[].login' | tail -10\`)
- If 6+ months since last submission, consider a fresh Show HN

Auto-generated by the Viral Amplifier Bot. No actions taken on your behalf — all suggestions require your manual approval." --label "viral-amplifier,milestone"`, { stdio: 'inherit' });
} catch { /* fine if it fails */ }

state.lastMilestone = newest;
state.firedAt = new Date().toISOString();
writeFileSync(STATE_PATH, JSON.stringify(state, null, 2));
console.log(`Milestone fired: ${newest}. LinkedIn template written.`);
